const tz = 'Australia/Sydney';
const now = new Date();

function getZonedYMD(date) {
  const fmt = new Intl.DateTimeFormat('en-CA', {
    timeZone: tz,
    year: 'numeric', month: '2-digit', day: '2-digit'
  });
  const parts = fmt.formatToParts(date);
  const obj = {};
  for (const p of parts) { if (p.type !== 'literal') obj[p.type] = p.value; }
  return `${obj.year}-${obj.month}-${obj.day}`;
}

function isoForSydneyMidnight(dateStr) {
  // Figure out Sydney's UTC offset for that date (AEST +10 or AEDT +11)
  const probe = new Date(`${dateStr}T12:00:00Z`);
  const dtf = new Intl.DateTimeFormat('en-US', {
    timeZone: tz,
    timeZoneName: 'shortOffset'
  });
  const parts = dtf.formatToParts(probe);
  const tzName = (parts.find(p => p.type === 'timeZoneName') || {}).value || 'GMT+10';
  const m = tzName.match(/GMT([+-])(\d{1,2})(?::?(\d{2}))?/);
  const sign = m ? m[1] : '+';
  const hh = m ? String(parseInt(m[2], 10)).padStart(2, '0') : '10';
  const mm = m && m[3] ? m[3] : '00';
  return `${dateStr}T00:00:00${sign}${hh}:${mm}`;
}

const todayStr = getZonedYMD(now);
const y = new Date(`${todayStr}T00:00:00Z`);
y.setUTCDate(y.getUTCDate() - 1);
const yStr = `${y.getUTCFullYear()}-${String(y.getUTCMonth() + 1).padStart(2, '0')}-${String(y.getUTCDate()).padStart(2, '0')}`;

const startOfDay = isoForSydneyMidnight(yStr);
const endOfDay = isoForSydneyMidnight(todayStr);

return [{ json: { startOfDay, endOfDay, dateString: yStr } }];

const rawItems = $('Read agent_logs').all();
const logs = [];
for (const it of rawItems) {
  const payload = it && it.json;
  if (!payload) continue;
  if (Array.isArray(payload)) {
    for (const row of payload) if (row && typeof row === 'object') logs.push(row);
  } else if (Array.isArray(payload.data)) {
    for (const row of payload.data) if (row && typeof row === 'object') logs.push(row);
  } else if (typeof payload === 'object') {
    logs.push(payload);
  }
}

const dateString = $('Compute Date Range').first().json.dateString;
const nowIso = new Date().toISOString();

if (logs.length === 0) {
  return [{
    json: {
      agent_name: 'system',
      date: dateString,
      total_logs: 0,
      error_count: 0,
      warn_count: 0,
      info_count: 0,
      success_rate: 100,
      avg_runtime_ms: null,
      estimated_cost_usd: 0,
      metadata: { note: 'no_logs_for_day', computed_at: nowIso }
    }
  }];
}

// claude-opus-4-7 pricing: $3/M input, $15/M output
const INPUT_PRICE = 0.000003;
const OUTPUT_PRICE = 0.000015;

const byAgent = new Map();
for (const log of logs) {
  const name = (log && log.agent_name) ? String(log.agent_name) : 'unknown';
  if (!byAgent.has(name)) byAgent.set(name, []);
  byAgent.get(name).push(log);
}

const rows = [];
for (const [agent_name, agentLogs] of byAgent) {
  const total_logs = agentLogs.length;
  let error_count = 0, warn_count = 0, info_count = 0;
  let runtimeSum = 0, runtimeCount = 0;
  let costSum = 0;
  const raw_log_ids = [];

  for (const log of agentLogs) {
    const level = (log && typeof log.level === 'string') ? log.level.toLowerCase() : '';
    if (level === 'error' || level === 'fatal') error_count++;
    else if (level === 'warn') warn_count++;
    else if (level === 'info') info_count++;

    if (log && log.id !== undefined && log.id !== null) raw_log_ids.push(log.id);

    const md = (log && log.metadata && typeof log.metadata === 'object') ? log.metadata : null;
    if (md) {
      if (typeof md.runtime_ms === 'number' && !Number.isNaN(md.runtime_ms)) {
        runtimeSum += md.runtime_ms;
        runtimeCount++;
      }
      const inTok = (typeof md.input_tokens === 'number' && !Number.isNaN(md.input_tokens)) ? md.input_tokens : 0;
      const outTok = (typeof md.output_tokens === 'number' && !Number.isNaN(md.output_tokens)) ? md.output_tokens : 0;
      costSum += inTok * INPUT_PRICE + outTok * OUTPUT_PRICE;
    }
  }

  const success_rate = total_logs === 0 ? 100 : ((total_logs - error_count) / total_logs) * 100;
  const avg_runtime_ms = runtimeCount > 0 ? runtimeSum / runtimeCount : null;

  rows.push({
    json: {
      agent_name,
      date: dateString,
      total_logs,
      error_count,
      warn_count,
      info_count,
      success_rate,
      avg_runtime_ms,
      estimated_cost_usd: costSum,
      metadata: { raw_log_ids, computed_at: nowIso }
    }
  });
}

return rows;
